from agno.agent import Agent
from agno.memory import MemoryClient

def monitor_memory_retention(agent, test_conversation, max_turns=10):
    memory_client = agent.memory
    initial_memory_count = len(memory_client.get_history())

    for i, turn in enumerate(test_conversation):
        agent.run(turn['input'])
        current_memory = memory_client.get_history()
        retention_rate = len(current_memory) / (initial_memory_count + i + 1)

        if retention_rate < 0.8:
            return {
                'turn': i,
                'retention_rate': retention_rate,
                'status': 'CONTEXT_LOSS',
                'is_failing': True
            }

    return {'status': 'PASS', 'is_failing': False}

from agno.memory import VectorStore
from agno.tools import ImageTool

def detect_multimodal_pollution(vector_store: VectorStore, image_tool: ImageTool):
    text_embeddings = vector_store.similarity_search('text conversation', k=5)
    image_embeddings = vector_store.similarity_search('image analysis', k=5)

    pollution_score = 0
    for emb in image_embeddings:
        if any('conversation' in str(doc.metadata) for doc in text_embeddings):
            pollution_score += 1

    return {
        'pollution_score': pollution_score / len(image_embeddings),
        'is_failing': pollution_score / len(image_embeddings) > 0.3
    }

