from agno.memory import VectorStore

class MultimodalVectorStore:
    def __init__(self):
        self.stores = {
            'text': VectorStore(),
            'image': VectorStore(namespace='image'),
            'audio': VectorStore(namespace='audio')
        }

    def add(self, content, modality='text'):
        self.stores[modality].add(content)

    def search(self, query, modality='text', k=5):
        return self.stores[modality].similarity_search(query, k=k)

# Usage in agent
agent = Agent(
    vector_store=MultimodalVectorStore(),
    tools=[ImageTool()]
)

from agno.agent import AgentTeam
from agno.memory import MemoryClient

class SynchronizedTeam(AgentTeam):
    def __init__(self, agents, shared_memory_id):
        super().__init__(agents)
        self.shared_memory = MemoryClient(session_id=shared_memory_id)

    def run_team(self, task):
        # Sync memory before team execution
        for agent in self.agents:
            agent.memory.merge(self.shared_memory.get_history())

        results = super().run_team(task)

        # Sync memory after execution
        for result in results:
            self.shared_memory.add_memory(result)
            for agent in self.agents:
                agent.memory.add_memory(result)

        return results

# Usage
team = SynchronizedTeam([agent1, agent2], 'team_session_1')
